INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-02309', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關圓錐角膜的敘述，下列何者錯誤？', '["特徵是中央或中央附近的角膜基質變薄，頂點外凸，變成不規則的圓錐狀，造成不規則散光", "疾病一般在青春期開始之後進展", "角膜弧度儀可見陡峭圓形區多位於角膜上方", "在很早期的病例可用眼鏡矯正規則性散光和低度的不規則性散光。進展到某種程度的病患可試戴硬式 隱形眼鏡改善視力，若不適合，可試特別設計的鞏膜鏡（scleral lens）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02310', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '一位隱形眼鏡配戴者出現劇痛、眼睛紅腫、分泌物增加，同時有畏光、流淚症狀。檢查發現有視力下降， 黏膿樣分泌物和瀰散性充血，最可能的診斷為：', '["過敏性結膜炎", "角膜潰瘍", "隱形眼鏡相關之乾眼症", "巨大乳突性結膜炎（giant papillary conjunctivitis）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02311', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於隱形眼鏡直徑（lens diameter）的敍述，下列何者錯誤？', '["軟式水膠球面隱形眼鏡，大部分直徑範圍在14～14.5 mm", "非離子性軟式水膠隱形眼鏡戴至眼內時，因眼內的溫度的影響會讓鏡片縮小", "硬式透氣隱形眼鏡，改變鏡片總直徑，不會影響鏡片的滑動穩定性", "硬式透氣隱形眼鏡，後表面光學區直徑（back optic zone diameter, BOZD）會比鏡片總直徑小約1～1.5 mm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 41, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02312', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何者不是角膜塑型術（orthokeratology）可能造成的併發症？', '["中心角膜磨損（corneal abrasion）", "角膜敏感度（sensitivity）下降", "增加高階像差（high-ordered aberrations）", "青光眼"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 42, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02313', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '解決交替視覺雙焦隱形眼鏡（alternating bifocal lens）發生的問題，下列何者正確？①看近模糊時提高子', '["交替不良時減少邊挑間隙", "看遠模糊時縮小鏡片直徑或降低稜鏡", "過度旋轉 時調整稜鏡朝向", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 43, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02314', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於隱形眼鏡清潔步驟的敘述，下列何者錯誤？', '["肥皂洗手完不需擦乾，直接碰觸隱形眼鏡較安全", "在使用臉部油性卸妝乳液前需先將隱形眼鏡取出", "選擇清潔液時需注意是否符合隱形眼鏡的材質", "沖洗隱形眼鏡時需用無菌生理食鹽水或多功能清潔液"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 44, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02315', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '引起隱形眼鏡急性紅眼症（contact lens acute red eye, CLARE）的主要原因為下列何者？', '["角膜缺氧", "隱形眼鏡清潔液引起過敏反應", "細菌的內毒素引起的炎性反應", "鏡片沉積物引起的過敏反應"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 45, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02316', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列那種情況較適合配戴硬式透氣隱形眼鏡？', '["碰撞型運動，如拳擊", "高危險運動，如極限運動", "有粉塵的運動環境", "有角膜散光者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 46, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02317', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '市面上最常見的多焦點軟式隱形眼鏡設計為下列那一種？', '["中央為看遠的同心圓設計", "交替性雙光設計", "中央為看近的同心圓設計", "繞射型光心設計"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 47, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02318', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何者不是一般隱形眼鏡護理液中消毒藥劑成分的常見功能？', '["消除可能引起感染之病原，包括細菌（bacteria）、真菌（fungi）、病毒（virus）及棘狀阿米巴原蟲 （acanthamoeba sp.）", "保持水合作用", "可達到及維持鏡片即取即戴的狀態", "保持隱形眼鏡表面活性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
